SET standard_conforming_strings = OFF;
DROP TABLE IF EXISTS "public"."footpaths" CASCADE;
DELETE FROM geometry_columns WHERE f_table_name = 'footpaths' AND f_table_schema = 'public';
BEGIN;
CREATE TABLE "public"."footpaths" ( "ogc_fid" SERIAL, CONSTRAINT "footpaths_pk" PRIMARY KEY ("ogc_fid") );
SELECT AddGeometryColumn('public','footpaths','wkb_geometry',2178,'MULTIPOLYGON',2);
CREATE INDEX "footpaths_wkb_geometry_geom_idx" ON "public"."footpaths" USING GIST ("wkb_geometry");
ALTER TABLE "public"."footpaths" ADD COLUMN "objectid" NUMERIC(10,0);
ALTER TABLE "public"."footpaths" ADD COLUMN "fid_footpa" NUMERIC(10,0);
ALTER TABLE "public"."footpaths" ADD COLUMN "local_" VARCHAR(3);
ALTER TABLE "public"."footpaths" ADD COLUMN "active" NUMERIC(10,0);
ALTER TABLE "public"."footpaths" ADD COLUMN "surftype" VARCHAR(50);
ALTER TABLE "public"."footpaths" ADD COLUMN "area" NUMERIC(19,11);
ALTER TABLE "public"."footpaths" ADD COLUMN "shape_leng" NUMERIC(19,11);
ALTER TABLE "public"."footpaths" ADD COLUMN "shape_area" NUMERIC(19,11);
COMMIT;
